CREATE TABLE IF NOT EXISTS ledger_principals (user_id text PRIMARY KEY, tenant_id text NOT NULL, legal_entity_id text NOT NULL, branch_id text NOT NULL, workspace_id text NOT NULL, till_id text NOT NULL, role text NOT NULL, authorized_branch_ids jsonb NOT NULL);
CREATE TABLE IF NOT EXISTS ledger_customers (customer_id text PRIMARY KEY, tenant_id text NOT NULL, legal_entity_id text NOT NULL, branch_id text NOT NULL, workspace_id text NOT NULL, name text NOT NULL, risk text NOT NULL, id_status text NOT NULL);
CREATE TABLE IF NOT EXISTS ledger_rates (tenant_id text NOT NULL, legal_entity_id text NOT NULL, branch_id text NOT NULL, workspace_id text NOT NULL, currency char(3) NOT NULL, units_per_cad numeric(24,12) NOT NULL CHECK (units_per_cad > 0), PRIMARY KEY (tenant_id,legal_entity_id,branch_id,workspace_id,currency));
CREATE TABLE IF NOT EXISTS ledger_till_balances (tenant_id text NOT NULL, legal_entity_id text NOT NULL, branch_id text NOT NULL, workspace_id text NOT NULL, till_id text NOT NULL, currency char(3) NOT NULL, available_amount numeric(24,2) NOT NULL CHECK (available_amount >= 0), PRIMARY KEY (tenant_id,legal_entity_id,branch_id,workspace_id,till_id,currency));
CREATE TABLE IF NOT EXISTS ledger_idempotency (tenant_id text NOT NULL, legal_entity_id text NOT NULL, branch_id text NOT NULL, workspace_id text NOT NULL, till_id text NOT NULL, operation text NOT NULL, idempotency_key text NOT NULL, response jsonb, PRIMARY KEY (tenant_id,legal_entity_id,branch_id,workspace_id,till_id,operation,idempotency_key));
CREATE TABLE IF NOT EXISTS ledger_transactions (transaction_id text PRIMARY KEY, transaction_ref text UNIQUE NOT NULL, tenant_id text NOT NULL, legal_entity_id text NOT NULL, branch_id text NOT NULL, workspace_id text NOT NULL, till_id text NOT NULL, customer_id text NOT NULL, actor_id text NOT NULL, from_currency char(3) NOT NULL, to_currency char(3) NOT NULL, input_amount numeric(24,2) NOT NULL, output_amount numeric(24,2) NOT NULL, rate numeric(24,12) NOT NULL, fee_cad numeric(24,2) NOT NULL, spread_cad numeric(24,2) NOT NULL, purpose text NOT NULL, source_of_funds text NOT NULL, posted_at timestamptz NOT NULL);
CREATE TABLE IF NOT EXISTS ledger_journal_entries (entry_id bigserial PRIMARY KEY, transaction_id text NOT NULL REFERENCES ledger_transactions(transaction_id), account_code text NOT NULL, side text NOT NULL CHECK (side IN ('debit','credit')), amount_cad numeric(24,2) NOT NULL, created_at timestamptz NOT NULL);
CREATE TABLE IF NOT EXISTS ledger_till_movements (movement_id bigserial PRIMARY KEY, transaction_id text NOT NULL REFERENCES ledger_transactions(transaction_id), currency char(3) NOT NULL, direction text NOT NULL CHECK (direction IN ('in','out')), amount numeric(24,2) NOT NULL, created_at timestamptz NOT NULL);
CREATE TABLE IF NOT EXISTS ledger_reversals (reversal_id text PRIMARY KEY, transaction_id text UNIQUE NOT NULL REFERENCES ledger_transactions(transaction_id), actor_id text NOT NULL, reason text NOT NULL, posted_at timestamptz NOT NULL);
CREATE TABLE IF NOT EXISTS ledger_reversal_entries (entry_id bigserial PRIMARY KEY, reversal_id text NOT NULL REFERENCES ledger_reversals(reversal_id), account_code text NOT NULL, side text NOT NULL CHECK (side IN ('debit','credit')), amount_cad numeric(24,2) NOT NULL, created_at timestamptz NOT NULL);
CREATE TABLE IF NOT EXISTS ledger_audit_events (event_id text PRIMARY KEY, tenant_id text NOT NULL, legal_entity_id text NOT NULL, branch_id text NOT NULL, workspace_id text NOT NULL, actor_id text NOT NULL, action text NOT NULL, target_id text NOT NULL, reason text, correlation_id text NOT NULL, created_at timestamptz NOT NULL);
CREATE OR REPLACE FUNCTION ledger_append_only() RETURNS trigger LANGUAGE plpgsql AS $$ BEGIN RAISE EXCEPTION 'append-only ledger record'; END; $$;
DROP TRIGGER IF EXISTS ledger_tx_immutable ON ledger_transactions; CREATE TRIGGER ledger_tx_immutable BEFORE UPDATE OR DELETE ON ledger_transactions FOR EACH ROW EXECUTE FUNCTION ledger_append_only();
DROP TRIGGER IF EXISTS ledger_journal_immutable ON ledger_journal_entries; CREATE TRIGGER ledger_journal_immutable BEFORE UPDATE OR DELETE ON ledger_journal_entries FOR EACH ROW EXECUTE FUNCTION ledger_append_only();
DROP TRIGGER IF EXISTS ledger_movements_immutable ON ledger_till_movements; CREATE TRIGGER ledger_movements_immutable BEFORE UPDATE OR DELETE ON ledger_till_movements FOR EACH ROW EXECUTE FUNCTION ledger_append_only();
DROP TRIGGER IF EXISTS ledger_audit_immutable ON ledger_audit_events; CREATE TRIGGER ledger_audit_immutable BEFORE UPDATE OR DELETE ON ledger_audit_events FOR EACH ROW EXECUTE FUNCTION ledger_append_only();
